const newsData = $input.first().json;
const newsCount = newsData.totalResults || 0;

if (newsCount > 0) {
  const severity = newsCount >= 3 ? 'HIGH' : 'MEDIUM';
  const payload = {
    zone_id: 'VAD-04',
    trigger_id: 'T4_CURFEW_DETECTED',
    severity,
    disruption_start: new Date().toISOString()
  };

  try {
    const resp = await fetch('http://host.docker.internal:8002/webhook/orchestrate', {
      method: 'POST',
      headers: { 'Content-Type': 'application/json' },
      body: JSON.stringify(payload)
    });
    const result = await resp.json();
    return [{ json: { triggered: true, details: `${newsCount} curfew articles found`, orchestrator: result } }];
  } catch (e) {
    return [{ json: { triggered: true, details: `${newsCount} curfew articles found`, error: e.message } }];
  }
}

return [{ json: { triggered: false, details: 'No curfew news detected' } }];
